Backtracking.python_template:
def backtrack(path, choices):
    if IS_COMPLETE(path):
        result.append(path[:])
        return
    for choice in choices:
        if IS_VALID(choice):
            path.append(choice)
            backtrack(path, NEXT_CHOICES)
            path.pop()  # undo

